var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"서윤 양, 무사했군요.","JPN":"シズカさん、ご無事でしたか。","ENG":"I'm glad you're unharmed, Seo Yoon.","TWN":"徐芸，你沒事就好。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_LAUGH"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L4_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"갑자기 통신이 두절돼서 걱정했어요. 다행입니다.","JPN":"急に通信が途絶えて心配していました。よかったです。","ENG":"We were worried when we lost contact. Thank goodness you're okay.","TWN":"突然中斷通訊，我還擔心你發生什麼事呢。幸好沒事。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"다행…… 이라고 하고 싶은데 그럴 수가 없네.","JPN":"よかった……って言いたいけどまだ言えないかな。","ENG":"I wish I could say I'm \\"okay\\"… but this doesn't look good.","TWN":"我也想說幸好……但情況似乎不太好。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"오면서 상황은 봤지?","JPN":"ここまで来る途中、状況は見たでしょ？","ENG":"You saw everything on your way here, right?","TWN":"你們來的時候有看到吧？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"네. 이 일대의 공간 구조가 미로처럼 조작됐더군요.","JPN":"はい、この一帯の空間構造が迷路のように操作されていました。","ENG":"Yes. The spatial structure around this area has been manipulated into some sort of maze.","TWN":"嗯，這一帶的空間結構似乎被人為操作成像是迷宮一樣。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"서윤 양과 마찬가지로, 함선과의 통신도 두절되었어요.","JPN":"シズカさんと同じく、艦船との通信も途絶えた状態です。","ENG":"We also lost contact with the ship, just like we did with you.","TWN":"我們也跟你一樣，無法和艦船通訊。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"맞아. 여긴 미카 말대로 방주라고 부르는 거대한 차원함선이었던 것 같아.","JPN":"ええ。ここはミカの言うとおり、箱舟と呼ばれる巨大な次元艦船だったみたい。","ENG":"Right. As Mika said, I think this used to be a giant dimensional ship, the sort they call an \\"Ark.\\"","TWN":"沒錯，這裡就像米卡說的那樣，原本是稱作方舟的次元艦船。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"그것도 공간을 조작할 수 있는 강력한 기능까지 탑재된.","JPN":"それも空間を操作できる強力な機能まで搭載されてる。","ENG":"In fact, it might be fitted with a powerful device to manipulate space itself.","TWN":"甚至還內建可以操作空間的強大功能。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"방주라…….","JPN":"箱舟ですか……","ENG":"An Ark, you say…","TWN":"方舟……"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"처음 듣는 함급이군요. 공간 조작이 가능한 함선에 대한 이야기는 더더욱.","JPN":"初めて聞く艦級ですね。空間操作が可能な艦船についても同じです。","ENG":"I've never heard of such a class of ship. Especially a ship that can manipulate space.","TWN":"我還是第一次聽到呢，竟然有可以操控時間的艦船的。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"하지만 경험한 사실을 부정하는 건 제 교육관에 포함되지 않습니다.","JPN":"しかし、経験した事実を否定することは私の教育観に反することです。","ENG":"However, denying empirical evidence would be contrary to my learning philosophy.","TWN":"但我沒聽過不代表不存在，"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이제부터 어떻게 할 생각인가요?","JPN":"これからどうするつもりですか？","ENG":"So what now?","TWN":"接下來該怎麼做呢？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"안으로 들어간 미나가 밖으로 나올 수 있으려면 이 함선의 기능을 정지시켜야 해.","JPN":"中に向かったミナが外に出るためには、この艦船の機能を停止させないと。","ENG":"In order for Mina to get back out here, we'll need to stop this ship from running.","TWN":"若是要讓裡面的米娜可以出來，就必須停止這艘艦船的功能。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"예를 들어 엔진을 부숴 버린다거나…….","JPN":"例えばエンジンを壊す、とかね。","ENG":"For instance, destroy the engine…","TWN":"像是破壞它的引擎之類的……"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"……그렇군요.","JPN":"……そうですね。","ENG":"I see...","TWN":"……原來如此。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"미카, 그리고 나이엘 학생. 두 사람은 함선의 동력부를 찾아 파괴해 주세요.","JPN":"ミカさん、ナイエルさん。二人は艦船の動力部を探して破壊してください。","ENG":"Mika and Naielle. Please find and destroy the ship's power source.","TWN":"米卡和奈爾同學，請你們找出艦船的發動機並且破壞它。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"네? 제가요?","JPN":"え？　私ですか？","ENG":"What? Me?","TWN":"嗯？你說我？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"아까도 말했지만 이 안에서 길을 찾을 가능성이 조금이라도 있는 사람은 미카뿐이에요.","JPN":"先ほども言いましたが、この中で正しい道を見つけられる可能性が高い人はミカさんだけです。","ENG":"As I mentioned, you have the best chance of navigating through this area.","TWN":"我剛才不是有說嗎？現在有可能在裡面找到路的人就只有米卡而已。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"나이엘 학생도 성격은 이상하지만, 실력만큼은 인정하고 있으니 도움이 될 겁니다.","JPN":"ナイエルさんも性格に多少問題はありますが、実力だけは認めるべきものなので助けになるでしょう。","ENG":"And as unorthodox as Naielle is in many ways, her combat capabilities should be most helpful.","TWN":"奈爾同學雖然個性古怪，但以他的實力來說應該是可以幫上忙。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"회장님도 같이 가면 되잖아요? 왜 여기 남을 것처럼……?","JPN":"会長は一緒に行かないんですか？　なんかここに残りそうな言い方を……","ENG":"But can't you come with us? Why are you speaking as if you're going to stay here?","TWN":"那會長你要去哪？為什麼不跟我們一起……"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"……감이 좋네. 검술만 뛰어난 게 아니었나 봐?","JPN":"……勘がいいね。剣術以外にも才能があったのね？","ENG":"…So you've got a pretty good instinct, huh. Swordplay isn't your only thing, is it?","TWN":"……不錯喔！看來你不只是劍術高明而已。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"허울만 좋게 총학생회장직을 맡고 있던 기억은 없습니다.","JPN":"肩書ばかりの生徒会長を務めているつもりはありませんので。","ENG":"As far as I can tell, I did not earn my tenure as Student President for nothing.","TWN":"我不記得我是一位虛有其表的學生會長。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그리고 이 정도로 강력한 침식파라면 못 느끼는 쪽이…… 이상하지요.","JPN":"そしてここまで強力な侵食波なら、感じないほうが……おかしいでしょう。","ENG":"Besides… it would be odd if I couldn't detect a Corruption Ray this potent.","TWN":"況且侵蝕波這麼強，我還感覺不到的話，那也未免太……奇怪。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"치, 침식파요?","JPN":"し、侵食波ですか？","ENG":"C-Corruption Ray?","TWN":"侵…侵蝕波？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"침식체는 방금 쓰러트린 게 전부 아니었어요?","JPN":"侵食体はさっき倒したのが全部じゃないんですか？","ENG":"You mean we didn't defeat all the C.O.s just now?","TWN":"我們剛處理掉的那些侵蝕體不是全部嗎？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"그럼 좋겠지만, 아직 시작도 못 했어.","JPN":"だったらよかったけど、まだ始まってもいないわ。","ENG":"I wish, but we barely even got started.","TWN":"我也希望，但那只是前菜而已，主餐都還沒上。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_HATE"}}}},{"id":"L38_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"내가 죽지 않을 만큼만 침식체를 보내서 가지고 놀고 있거든.","JPN":"私が死なない程度の数の侵食体を送って弄んでいるの。","ENG":"He's sending me just enough C.O.s so he can keep toying with me without me dying.","TWN":"一直有侵蝕波送上來，但又好像沒有要置我於死。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"저 침식파의 근원이 말인가요?","JPN":"あの侵食波の根源がですか？","ENG":"He, who? You mean the source of this Corruption Ray?","TWN":"你是說侵蝕波的來源嗎？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"맞아, 황태자인지 뭔지 하는 망할 변태 자식!","JPN":"そう、あの皇太子とかいう変態め！","ENG":"That's right. That creepy pervert who calls himself a prince or something!","TWN":"對！就是那個叫 皇太子還什麼的變態傢伙！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"보나마나 지금도 저기 안개 너머에서 우릴 구경하고 있을걸?","JPN":"どうせ今もあの霧の向こうで私たちのことを見物してるんじゃない？","ENG":"He's probably still watching us from beyond that fog right there!","TWN":"我用膝蓋想也知道，他現在一定也正在霧氣那邊看我們的好戲。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"<color=#ff3636>하하, 평민들에게 발악할 기회를 주는 것도 제왕의 미덕이지.</color>","JPN":"<color=#ff3636>ハハハ、平民にあがく機会を与えるのも帝王の美徳だろう。</color>","ENG":"<color=#ff3636>Haha, a true regent is gracious enough to grant his subjects a chance to fight.</color>","TWN":"<color=#ff3636>呵呵～讓平民老百姓有苦苦哀求的機會是身為君王的美德。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"<color=#ff3636>단숨에 짓밟아 버리면 흥이 깨지지 않느냐.</color>","JPN":"<color=#ff3636>一息で踏み潰してしまったら興ざめじゃないか。</color>","ENG":"<color=#ff3636>It'd be far too boring to crush them all at once, after all.</color>","TWN":"<color=#ff3636>一下就捏死他們不是很無趣嗎？呵呵。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"<color=#ff3636>너무 겁먹지 마라. 지금 막 공연이 절정부에 도달했으니.</color>","JPN":"<color=#ff3636>そう恐れるな。公演はまさに最高潮だ。</color>","ENG":"<color=#ff3636>Do not be dismayed, however. This show is nearing its climax.</color>","TWN":"<color=#ff3636>先別怕，劇情正進入高潮，</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"<color=#ff3636>너희한테 관심을 주는 것은 공연이 막을 내린 뒤로 하겠다.</color>","JPN":"<color=#ff3636>貴様たちに関心を寄せるのは公演の幕が下りた後にしよう。</color>","ENG":"<color=#ff3636>I shall tend to thee once this performance is over.</color>","TWN":"<color=#ff3636>等落幕演完後我再來處理你們。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"뭐, 뭐야? 방금?","JPN":"な、なに？　今のは！？","ENG":"W-what the? What was that just now?","TWN":"現…現在是怎樣？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"목소리만 들었는데 속이 울렁거리고 머리가 아파…….","JPN":"声を聞いただけなのに、胃がムカムカして頭が痛い……","ENG":"I only heard a voice, but I'm all nauseous, and my head's killing me…","TWN":"光是聽到聲音我就覺得一陣頭痛噁心想吐……"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L3_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"이게 침식파란 말이야……? 그동안 겪어 봤던 거랑 너무 다르잖아?","JPN":"これが侵食波なの……？　今までのと全然違う！","ENG":"This is a Corruption Ray? It's way different from anything I've ever experienced!","TWN":"這就是侵蝕波嗎……？和我們之前經歷過的完全不同層次。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"아직도 거기서 뭐 하는 거야?","JPN":"何ぼーっとしてるの？","ENG":"What are you guys still doing there?","TWN":"還傻在那幹嘛？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"지금이 기회야! 저 녀석이 우릴 얕잡아보는 동안 어서 가!","JPN":"今がチャンスよ！　あいつが私たちを見ている間に行って！","ENG":"Now's our chance! Get going while he's still underestimating us!","TWN":"現在就是機會！趁那傢伙注意力不在我們身上的時候快去！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"으, 응! 알았어!","JPN":"う、うん！　わかった！","ENG":"O-Okay! Got it!","TWN":"唔！好！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"따라와, 나이엘! 이쪽이야!","JPN":"ついてきて、ナイエル！　こっちだよ！","ENG":"Follow me, Naielle! It's this way!","TWN":"奈爾跟我來！從這裡！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"쳇……! 나한테 명령하지 마!","JPN":"ちっ……！　私に命令しないでよ！","ENG":"Hmph…! Don't you boss me around!","TWN":"嗟……！你少命令我！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};